// ============================================================
// PROYECCI?N TOTAL DE AHORRO ? DIRECTO + ADICIONAL
// ============================================================
const params = $('Set | All Params').first().json;
const leadsProyectados = Number(params.leads_interacted_proyectados);
const interactedRaw = $('Interacted Leads Base').all().map(i => i.json);
const todos = items.map(i => i.json);
const baseLeadsSet = new Set(interactedRaw.map(r => Number(r.lead_id)));
const baseLeadsCount = baseLeadsSet.size;
const scale = baseLeadsCount > 0 ? leadsProyectados / baseLeadsCount : 0;
const SEMANAS_POR_MES = 4.33;
const salarioMensualBob = Number(params.salario_mensual_asistente_bob);
const horasSemana = Number(params.horas_semana);
const costoHoraBob = Math.round((salarioMensualBob / (horasSemana * SEMANAS_POR_MES)) * 100) / 100;
function n(v){ const x = Number(v); return Number.isFinite(x) ? x : 0; }
function round(v,d=2){ const m=Math.pow(10,d); return Math.round(n(v)*m)/m; }
function firstLeadKeys(item){ return Object.keys((item.detalle_tecnico?.desglose_por_lead || [])[0] || {}); }
function isBotWorkload(item){ return item.tipo_stats === 'bot_workload'; }
function isLeadRegistration(item){ return item.tipo_stats === 'lead_registration'; }
function isSummaryUpdates(item){ return item.tipo_stats === 'summary_updates'; }
function isPipelineMoves(item){ return item.tipo_stats === 'pipeline_moves'; }
function isInventoryOps(item){ return item.tipo_stats === 'inventory_ops'; }
function isSuggester(item){ return firstLeadKeys(item).includes('modelos_evaluados_total'); }
function isDetails(item){ return firstLeadKeys(item).includes('proyectos_compilados_total'); }
function isScheduler(item){ const keys = firstLeadKeys(item); return keys.includes('total_solicitudes') && !isBotWorkload(item) && !isLeadRegistration(item) && !isSummaryUpdates(item) && !isPipelineMoves(item); }
const components = { lead_registration: todos.find(isLeadRegistration), bot_workload: todos.find(isBotWorkload), suggester: todos.find(isSuggester), details: todos.find(isDetails), scheduler: todos.find(isScheduler), summary_updates: todos.find(isSummaryUpdates), pipeline_moves: todos.find(isPipelineMoves), inventory_ops: todos.find(isInventoryOps) };
const required = ['lead_registration','bot_workload','suggester','details','scheduler','summary_updates','pipeline_moves','inventory_ops'];
const missing = required.filter(k => !components[k]);
if (!baseLeadsCount || missing.length) return [{ json: { tipo_salida: 'error_missing_input_branch_v2', error: 'Faltan ramas para calcular la proyecci?n completa', missing, interacted_rows: baseLeadsCount, received_tipo_stats: todos.map(x => x.tipo_stats || null), received_keys: todos.map(x => firstLeadKeys(x)) } }];
function hoursOf(item, field='horas_ahorradas'){ return n(item?.resumen_ejecutivo?.[field]); }
function bobOfHours(h){ return round(h * costoHoraBob, 2); }
const directKeys = ['lead_registration','bot_workload','suggester','details','scheduler'];
const additionalLeadKeys = ['summary_updates','pipeline_moves'];
const directRealHours = round(directKeys.reduce((s,k)=>s+hoursOf(components[k]),0),2);
const directProjectedHours = round(directRealHours * scale, 2);
const additionalLeadRealHours = round(additionalLeadKeys.reduce((s,k)=>s+hoursOf(components[k]),0),2);
const additionalLeadProjectedHours = round(additionalLeadRealHours * scale, 2);
const inventorySetupHours = hoursOf(components.inventory_ops, 'horas_creacion_inventario');
const inventoryRecurringHours = hoursOf(components.inventory_ops, 'horas_revision_disponibilidad_mes');
const additionalMonthlyProjectedHours = round(additionalLeadProjectedHours + inventoryRecurringHours, 2);
const additionalReferenceTotalHours = round(additionalMonthlyProjectedHours + inventorySetupHours, 2);
const totalMonthlyProjectedHours = round(directProjectedHours + additionalMonthlyProjectedHours, 2);
const totalReferenceWithSetupHours = round(directProjectedHours + additionalReferenceTotalHours, 2);
function compSummary(k){ const item = components[k]; const rawH = hoursOf(item); const isInventory = k === 'inventory_ops'; const projectedH = isInventory ? rawH : rawH * scale; return { componente: k, clasificacion_ahorro: item.clasificacion_ahorro || null, scale_mode: item.scale_mode || (isInventory ? 'inventory_not_lead_scaled' : 'per_lead'), leads_con_uso: item.resumen_ejecutivo?.leads_atendidos ?? null, horas_reales_periodo: round(rawH,2), horas_proyectadas_o_referencia: round(projectedH,2), ahorro_bob_proyectado_o_referencia: bobOfHours(projectedH), resumen_ejecutivo: item.resumen_ejecutivo || {} }; }
const porLead = {};
for (const lead_id of baseLeadsSet) porLead[lead_id] = { lead_id };
for (const [k,item] of Object.entries(components)) {
  for (const r of (item.detalle_tecnico?.desglose_por_lead || [])) {
    const id = Number(r.lead_id); if (!porLead[id]) continue;
    porLead[id]['horas_' + k] = n(r.horas_ahorradas);
    porLead[id]['ahorro_' + k + '_bob'] = n(r.ahorro_equivalente_bob);
  }
}
for (const l of Object.values(porLead)) { l.horas_directas = round(directKeys.reduce((s,k)=>s+n(l['horas_' + k]),0),4); l.horas_adicionales = round(additionalLeadKeys.reduce((s,k)=>s+n(l['horas_' + k]),0),4); }
return [{ json: { tipo_salida: 'projection_total_ahorro_interacted_v2', scope: { base: 'Leads (CTWA/MM/Active) with Bot & Lead Reply', periodo_inicio: params.period_start, periodo_fin: params.period_end, target_user_id: params.target_user_id, leads_interacted_reales_periodo: baseLeadsCount, leads_interacted_proyectados: leadsProyectados, escala_proyeccion_leads: round(scale,4) }, resumen_capas: { ahorro_operativo_directo: { componentes: directKeys, horas_reales_periodo: directRealHours, horas_proyectadas_mes: directProjectedHours, ahorro_proyectado_mes_bob: bobOfHours(directProjectedHours) }, valor_operativo_adicional_automatizado: { componentes_lead_scaled: additionalLeadKeys, horas_lead_scaled_reales_periodo: additionalLeadRealHours, horas_lead_scaled_proyectadas_mes: additionalLeadProjectedHours, horas_revision_disponibilidad_mes: round(inventoryRecurringHours,2), horas_creacion_inventario_setup: round(inventorySetupHours,2), horas_adicionales_recurrentes_mes: additionalMonthlyProjectedHours, valor_adicional_recurrente_mes_bob: bobOfHours(additionalMonthlyProjectedHours), horas_adicionales_referencia_con_setup: additionalReferenceTotalHours, valor_adicional_referencia_con_setup_bob: bobOfHours(additionalReferenceTotalHours) }, total_recurrente_mes: { horas: totalMonthlyProjectedHours, bob: bobOfHours(totalMonthlyProjectedHours) }, total_referencia_con_setup_inventario: { horas: totalReferenceWithSetupHours, bob: bobOfHours(totalReferenceWithSetupHours) } }, resumen_por_componente: Object.fromEntries(required.map(k => [k, compSummary(k)])), detalle_tecnico: { costo_por_hora_asistente_humano_bob: costoHoraBob, supuestos_nuevos: { segundos_por_registro_lead: params.segundos_por_registro_lead, horas_idle_para_interaccion_resumen: params.horas_idle_para_interaccion_resumen, segundos_por_actualizacion_resumen_interaccion: params.segundos_por_actualizacion_resumen_interaccion, segundos_por_movimiento_embudo: params.segundos_por_movimiento_embudo, minutos_por_proyecto_inventario: params.minutos_por_proyecto_inventario, minutos_por_listing_independiente_inventario: params.minutos_por_listing_independiente_inventario, minutos_revision_disponibilidad_proyecto: params.minutos_revision_disponibilidad_proyecto, dias_ciclo_revision_disponibilidad_proyecto: params.dias_ciclo_revision_disponibilidad_proyecto }, desglose_por_lead: Object.values(porLead) } } }];

// ============================================================
// ESTADÍSTICAS SUGGESTER + TIEMPO AHORRADO
// ============================================================
// Entrada: filas de "Suggester Calls" (una fila por solicitud de búsqueda)
// Lee los parámetros de tiempo/salario del nodo "Set | Suggester Params"
// Salida: un item con las estadísticas resumidas
// ============================================================
//
// MODELO DE TIEMPO (v2):
// El tiempo "ahorrado" en BOB ya NO se calcula multiplicando por la
// cantidad de modelos evaluados (eso daba resultados irreales, ~33 min
// por solicitud). Ahora se usa un tiempo FIJO y realista por solicitud
// (minutos_por_solicitud_humano) — el tiempo que tomaría a un asistente
// humano revisar brochures/precios y responder a un cliente.
//
// La "profundidad" del bot (cuántos modelos evaluó vs. lo que un humano
// alcanzaría a revisar en ese mismo tiempo) se reporta como un dato
// APARTE, no mezclado con el cálculo de dinero — para no inflar el
// número de costo con una comparación que en realidad es de calidad,
// no de tiempo.
//
// minutos_por_solicitud_humano y opciones_evaluadas_humano_asumidas son
// PLACEHOLDERS sin validar — hay que confirmar con el equipo real
// (ej. preguntarle a Ysela cuánto le toma revisar un brochure y comparar
// contra lo que pide un cliente).
// ============================================================

const params = $('Set | All Params').first().json;

const minutosPorSolicitudHumano = Number(params.minutos_por_solicitud_humano_para_suggester);
const modelosQueRevisariaUnHumano = Number(params.modelos_que_revisaria_un_humano_para_suggester);

const SEMANAS_POR_MES = 4.33;
const salarioMensualBob = Number(params.salario_mensual_asistente_bob);
const horasSemana = Number(params.horas_semana);
const horasMes = horasSemana * SEMANAS_POR_MES;
const costoHoraBob = Math.round((salarioMensualBob / horasMes) * 100) / 100;

function numField(f, campo) {
  const v = f[campo];
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isNaN(n) ? null : n;
}

const filas = items.map(i => i.json);

// --- LEADS ÚNICOS ---
const leadsSet = new Set(filas.map(f => f.lead_id));
const leadsUnicos = leadsSet.size;
const totalSolicitudes = filas.length;
const solicitudesPorLead = leadsUnicos > 0
  ? Math.round((totalSolicitudes / leadsUnicos) * 100) / 100
  : null;

// --- RESULTADOS POR TIPO ---
const conteoResultados = { coincidencias: 0, sin_coincidencia: 0, invalidas: 0, otro: 0 };
for (const f of filas) {
  if (f.request_result === 'matched') conteoResultados.coincidencias++;
  else if (f.request_result === 'no_match') conteoResultados.sin_coincidencia++;
  else if (f.request_result === 'invalid') conteoResultados.invalidas++;
  else conteoResultados.otro++;
}

const filasCoincidencia = filas.filter(f => f.request_result === 'matched');
const coincidenciasExactas = filasCoincidencia.filter(f => f.has_exact === true).length;
const porcentajeCoincidenciasExactas = filasCoincidencia.length > 0
  ? Math.round((coincidenciasExactas / filasCoincidencia.length) * 1000) / 10
  : null;

// --- PROMEDIOS Y TOTALES EVALUADOS (ignora nulos) ---
function promedio(campo) {
  const valores = filas.map(f => numField(f, campo)).filter(v => v !== null);
  if (valores.length === 0) return null;
  const suma = valores.reduce((a, b) => a + b, 0);
  return Math.round((suma / valores.length) * 100) / 100;
}
function sumar(campo) {
  const valores = filas.map(f => numField(f, campo)).filter(v => v !== null);
  return valores.reduce((a, b) => a + b, 0);
}

const promedioProyectos = promedio('proyectos_evaluados');
const promedioModelos   = promedio('modelos_evaluados_criterio');
const promedioUnidades  = promedio('unidades_evaluadas');
const promedioOpciones  = promedio('opciones_presentadas');

const totalProyectosEvaluados = sumar('proyectos_evaluados');
const totalModelosEvaluados   = sumar('modelos_evaluados_criterio');
const totalUnidadesEvaluadas  = sumar('unidades_evaluadas');
const totalOpcionesPresentadas = sumar('opciones_presentadas');

// --- ESTADÍSTICAS DETALLADAS (min/max/mediana por métrica) ---
function estadisticas(campo) {
  const valores = filas.map(f => numField(f, campo)).filter(v => v !== null).sort((a, b) => a - b);
  if (valores.length === 0) return { minimo: null, maximo: null, mediana: null };
  const mid = Math.floor(valores.length / 2);
  const mediana = valores.length % 2 !== 0
    ? valores[mid]
    : Math.round(((valores[mid - 1] + valores[mid]) / 2) * 100) / 100;
  return {
    minimo: valores[0],
    maximo: valores[valores.length - 1],
    mediana: mediana
  };
}

const estadisticasProyectos = estadisticas('proyectos_evaluados');
const estadisticasModelos   = estadisticas('modelos_evaluados_criterio');
const estadisticasUnidades  = estadisticas('unidades_evaluadas');
const estadisticasOpciones  = estadisticas('opciones_presentadas');

// --- DISTRIBUCIÓN DE SOLICITUDES POR LEAD ---
const conteoSolicitudesPorLeadTemp = {};
for (const f of filas) {
  conteoSolicitudesPorLeadTemp[f.lead_id] = (conteoSolicitudesPorLeadTemp[f.lead_id] || 0) + 1;
}
const solicitudesPorLeadValores = Object.values(conteoSolicitudesPorLeadTemp);
const leadsConUnaSolicitud = solicitudesPorLeadValores.filter(n => n === 1).length;
const leadsConVariasSolicitudes = solicitudesPorLeadValores.filter(n => n > 1).length;
const maxSolicitudesDeUnMismoLead = solicitudesPorLeadValores.length > 0
  ? Math.max(...solicitudesPorLeadValores)
  : null;

// --- PROFUNDIDAD DEL BOT vs. LO QUE ALCANZARÍA UN HUMANO ---
// Base de comparación: modelos_evaluados_criterio = el total de modelos
// que el bot revisó y que SÍ cumplían lo esencial pedido (operación,
// tipología, dormitorios) — NO es lo mismo que opciones_presentadas
// (esas son solo las pocas tarjetas finales que se le muestran al
// cliente; tanto el bot como un humano terminarían mostrando pocas).
// Lo que diferencia es cuánto se revisó ANTES de llegar a esas pocas.
const vecesMasModelosEvaluados = (promedioModelos != null && modelosQueRevisariaUnHumano > 0)
  ? Math.round((promedioModelos / modelosQueRevisariaUnHumano) * 10) / 10
  : null;

// --- TIEMPO Y COSTO (TOTAL DEL MES) ---
// Tiempo fijo y realista por solicitud, no dependiente de cuántos
// modelos evaluó el bot.
const segundosTotales = totalSolicitudes * minutosPorSolicitudHumano * 60;
const horasAhorradas = Math.round((segundosTotales / 3600) * 100) / 100;
const costoEquivalenteBob = Math.round(horasAhorradas * costoHoraBob * 100) / 100;

// --- TIEMPO Y COSTO PROMEDIO POR LEAD ---
const horasPromedioPorLead = leadsUnicos > 0
  ? Math.round((horasAhorradas / leadsUnicos) * 100) / 100
  : null;
const costoPromedioPorLeadBob = leadsUnicos > 0
  ? Math.round((costoEquivalenteBob / leadsUnicos) * 100) / 100
  : null;

// --- DESGLOSE POR LEAD ---
const porLeadMap = {};
for (const f of filas) {
  const proyectos = numField(f, 'proyectos_evaluados') || 0;
  const modelos   = numField(f, 'modelos_evaluados_criterio') || 0;

  if (!porLeadMap[f.lead_id]) {
    porLeadMap[f.lead_id] = {
      lead_id: f.lead_id,
      total_solicitudes: 0,
      proyectos_evaluados_total: 0,
      modelos_evaluados_total: 0
    };
  }
  const l = porLeadMap[f.lead_id];
  l.total_solicitudes++;
  l.proyectos_evaluados_total += proyectos;
  l.modelos_evaluados_total += modelos;
}

const porLead = Object.values(porLeadMap).map(l => {
  const horas = Math.round((l.total_solicitudes * minutosPorSolicitudHumano / 60) * 100) / 100;
  return {
    lead_id: l.lead_id,
    total_solicitudes: l.total_solicitudes,
    proyectos_evaluados_total: l.proyectos_evaluados_total,
    modelos_evaluados_total: l.modelos_evaluados_total,
    horas_ahorradas: horas,
    ahorro_equivalente_bob: Math.round(horas * costoHoraBob * 100) / 100
  };
}).sort((a, b) => b.ahorro_equivalente_bob - a.ahorro_equivalente_bob);

return [{
  json: {
    // ========================================================
    // RESUMEN EJECUTIVO — orden que sigue la lógica del cálculo:
    // volumen -> supuesto de tiempo -> horas -> costo/hora -> costo total
    // ========================================================
    resumen_ejecutivo: {
      leads_atendidos: leadsUnicos,
      solicitudes_procesadas: totalSolicitudes,
      minutos_que_tomaria_a_un_humano_por_solicitud: minutosPorSolicitudHumano,
      horas_ahorradas: horasAhorradas,
      costo_por_hora_de_un_asistente_humano_bob: costoHoraBob,
      ahorro_equivalente_bob: costoEquivalenteBob,
      modelos_promedio_evaluados_por_bot_por_solicitud: promedioModelos,
      modelos_que_revisaria_un_humano_en_ese_mismo_tiempo: modelosQueRevisariaUnHumano,
      veces_mas_modelos_evaluados_que_un_humano: vecesMasModelosEvaluados
    },

    // ========================================================
    // DETALLE TÉCNICO — para verificar los números de arriba
    // ========================================================
    detalle_tecnico: {
      resultados: {
        coincidencias: conteoResultados.coincidencias,
        sin_coincidencia: conteoResultados.sin_coincidencia,
        invalidas: conteoResultados.invalidas,
        porcentaje_coincidencias_exactas: porcentajeCoincidenciasExactas
      },
      promedios_evaluados: {
        proyectos_promedio: promedioProyectos,
        modelos_promedio: promedioModelos,
        unidades_promedio: promedioUnidades,
        opciones_promedio: promedioOpciones
      },
      totales_evaluados: {
        proyectos_evaluados_total: totalProyectosEvaluados,
        modelos_evaluados_total: totalModelosEvaluados,
        unidades_evaluadas_total: totalUnidadesEvaluadas,
        opciones_presentadas_total: totalOpcionesPresentadas
      },
      estadisticas_por_metrica: {
        proyectos_evaluados: estadisticasProyectos,
        modelos_evaluados_criterio: estadisticasModelos,
        unidades_evaluadas: estadisticasUnidades,
        opciones_presentadas: estadisticasOpciones
      },
      distribucion_solicitudes_por_lead: {
        leads_con_una_sola_solicitud: leadsConUnaSolicitud,
        leads_con_varias_solicitudes: leadsConVariasSolicitudes,
        max_solicitudes_de_un_mismo_lead: maxSolicitudesDeUnMismoLead
      },
      supuestos_usados: {
        minutos_que_tomaria_a_un_humano_por_solicitud: minutosPorSolicitudHumano,
        modelos_que_revisaria_un_humano_en_ese_mismo_tiempo: modelosQueRevisariaUnHumano,
        salario_mensual_de_un_asistente_humano_bob: salarioMensualBob,
        horas_de_trabajo_por_semana: horasSemana
      },
      promedio_por_lead: {
        solicitudes_por_lead: solicitudesPorLead,
        horas_promedio_por_lead: horasPromedioPorLead,
        costo_promedio_por_lead_bob: costoPromedioPorLeadBob
      },
      desglose_por_lead: porLead
    }
  }
}];

// ============================================================
// ESTADÍSTICAS PROPERTY DETAILS + TIEMPO AHORRADO
// ============================================================
// Entrada: filas de "Property Details Calls"
// Lee los parámetros del nodo "Set | Details Params"
//
// Tiempo = (proyectos_compilados × segundos_por_proyecto)
//        + (unidades_compiladas × segundos_por_unidad)
// Cada solicitud contribuye según lo que realmente compiló, no un
// tiempo fijo — a diferencia de Suggester, aquí el conteo por
// solicitud es naturalmente pequeño y no infla el número.
// ============================================================

const params = $('Set | All Params').first().json;

const segundosPorProyecto = Number(params.segundos_por_proyecto_para_details);
const segundosPorUnidad = Number(params.segundos_por_unidad_para_details);

const SEMANAS_POR_MES = 4.33;
const salarioMensualBob = Number(params.salario_mensual_asistente_bob);
const horasSemana = Number(params.horas_semana);
const horasMes = horasSemana * SEMANAS_POR_MES;
const costoHoraBob = Math.round((salarioMensualBob / horasMes) * 100) / 100;

function numField(f, campo) {
  const v = f[campo];
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isNaN(n) ? null : n;
}

const filas = items.map(i => i.json);

// --- LEADS ÚNICOS ---
const leadsSet = new Set(filas.map(f => f.lead_id));
const leadsUnicos = leadsSet.size;
const totalSolicitudes = filas.length;
const solicitudesPorLead = leadsUnicos > 0
  ? Math.round((totalSolicitudes / leadsUnicos) * 100) / 100
  : null;

// --- RESPONSE_TYPE (distribución) ---
const conteoResponseType = {};
for (const f of filas) {
  const key = f.response_type || 'desconocido';
  conteoResponseType[key] = (conteoResponseType[key] || 0) + 1;
}

// --- PROMEDIOS Y TOTALES ---
function promedio(campo) {
  const valores = filas.map(f => numField(f, campo)).filter(v => v !== null);
  if (valores.length === 0) return null;
  const suma = valores.reduce((a, b) => a + b, 0);
  return Math.round((suma / valores.length) * 100) / 100;
}
function sumar(campo) {
  const valores = filas.map(f => numField(f, campo)).filter(v => v !== null);
  return valores.reduce((a, b) => a + b, 0);
}

const promedioProyectos = promedio('proyectos_compilados');
const promedioUnidades  = promedio('unidades_compiladas');
const promedioListadosIndep = promedio('listados_independientes_compilados');

const totalProyectosCompilados = sumar('proyectos_compilados');
const totalUnidadesCompiladas  = sumar('unidades_compiladas');
const totalListadosIndep = sumar('listados_independientes_compilados');

// --- TIEMPO Y COSTO (TOTAL DEL MES) ---
let segundosTotales = 0;
for (const f of filas) {
  const proyectos = numField(f, 'proyectos_compilados') || 0;
  const unidades = numField(f, 'unidades_compiladas') || 0;
  segundosTotales += (proyectos * segundosPorProyecto) + (unidades * segundosPorUnidad);
}
const horasAhorradas = Math.round((segundosTotales / 3600) * 100) / 100;
const ahorroEquivalenteBob = Math.round(horasAhorradas * costoHoraBob * 100) / 100;

// --- PROMEDIO POR LEAD ---
const horasPromedioPorLead = leadsUnicos > 0
  ? Math.round((horasAhorradas / leadsUnicos) * 100) / 100
  : null;
const ahorroPromedioPorLeadBob = leadsUnicos > 0
  ? Math.round((ahorroEquivalenteBob / leadsUnicos) * 100) / 100
  : null;

// --- DESGLOSE POR LEAD ---
const porLeadMap = {};
for (const f of filas) {
  const proyectos = numField(f, 'proyectos_compilados') || 0;
  const unidades = numField(f, 'unidades_compiladas') || 0;
  const segundos = (proyectos * segundosPorProyecto) + (unidades * segundosPorUnidad);

  if (!porLeadMap[f.lead_id]) {
    porLeadMap[f.lead_id] = {
      lead_id: f.lead_id,
      total_solicitudes: 0,
      proyectos_compilados_total: 0,
      unidades_compiladas_total: 0,
