  ? Math.round((totalSolicitudes / leadsUnicos) * 100) / 100
  : null;

// --- MODALIDAD (distribución) ---
const conteoModalidad = {};
for (const f of filas) {
  const key = f.modality || 'desconocido';
  conteoModalidad[key] = (conteoModalidad[key] || 0) + 1;
}

